import os
import requests

_BRAVE_SESSION = requests.Session()
_BRAVE_SESSION.headers["Accept"] = "application/json"
_BRAVE_SESSION.headers["Accept-Encoding"] = "gzip"
_BRAVE_SESSION.headers["X-Subscription-Token"] = os.environ["BRAVE_API_KEY"]

SEARCH_WEB_TOOL = {
    "name": "search_web",
    "description": (
        "Search the web for recent information using Brave Search. "
        "Returns up to 10 results with title, URL, and a text snippet. "
        "Use for questions about current events, documentation, prices, or "
        "any topic where you need up-to-date information not in your training data."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {"type": "string", "description": "Search keywords."},
            "count": {"type": "integer", "minimum": 1, "maximum": 10,
                       "description": "Number of results (default 5)."}
        },
        "required": ["query"]
    }
}

def search_web(query: str, count: int = 5) -> dict:
    try:
        resp = _BRAVE_SESSION.get(
            "https://api.search.brave.com/res/v1/web/search",
            params={"q": query, "count": min(count, 10)},
            timeout=10,
        )
    except requests.Timeout:
        return {"error": "SERVICE_UNAVAILABLE", "message": "Search timed out.", "retryable": True}
    if resp.status_code == 429:
        return {"error": "RATE_LIMITED", "message": "Search rate limit reached.",
                "retryable": True, "retry_after": 5}
    if not resp.ok:
        return {"error": "SERVICE_UNAVAILABLE",
                "message": f"Search API returned HTTP {resp.status_code}.", "retryable": True}
    data = resp.json()
    results = [
        {
            "title": item.get("title", ""),
            "url": item.get("url", ""),
            "snippet": item.get("description", ""),
        }
        for item in data.get("web", {}).get("results", [])
    ]
    return {"query": query, "results": results, "count": len(results)}

import re
from bs4 import BeautifulSoup

FETCH_PAGE_TOOL = {
    "name": "fetch_page",
    "description": (
        "Fetch and return the readable text content of a web page. "
        "Strips HTML tags, navigation, and ads. "
        "Returns up to 6000 characters of the main content. "
        "Use after search_web to read the full content of a promising result."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "url": {"type": "string", "description": "The URL to fetch."}
        },
        "required": ["url"]
    }
}

MAX_CHARS = 6000
_SCRAPE_SESSION = requests.Session()
_SCRAPE_SESSION.headers["User-Agent"] = "Mozilla/5.0 (compatible; research-agent/1.0)"

def fetch_page(url: str) -> dict:
    # Basic URL validation — only http/https
    if not re.match(r'^https?://', url):
        return {"error": "VALIDATION_ERROR",
                "message": "url must start with http:// or https://", "retryable": False}
    try:
        resp = _SCRAPE_SESSION.get(url, timeout=10, allow_redirects=True)
    except requests.Timeout:
        return {"error": "SERVICE_UNAVAILABLE", "message": f"Timed out fetching {url}", "retryable": True}
    except requests.RequestException as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc), "retryable": True}
    if not resp.ok:
        return {"error": "NOT_FOUND" if resp.status_code == 404 else "SERVICE_UNAVAILABLE",
                "message": f"HTTP {resp.status_code} for {url}", "retryable": resp.status_code >= 500}
    content_type = resp.headers.get("Content-Type", "")
    if "text/html" not in content_type:
        return {"error": "VALIDATION_ERROR",
                "message": f"URL returned {content_type!r}, not HTML.", "retryable": False}
    soup = BeautifulSoup(resp.text, "html.parser")
    # Remove non-content elements
    for tag in soup(["script", "style", "nav", "footer", "header", "aside", "form"]):
        tag.decompose()
    title = soup.title.string.strip() if soup.title else ""
    text = " ".join(soup.get_text(separator=" ").split())  # collapse whitespace
    return {
        "url": url,
        "title": title,
        "text": text[:MAX_CHARS],
        "truncated": len(text) > MAX_CHARS,
    }

