def _check_domain(url: str) -> str | None:
    """Return error message if domain not allowed, else None."""
    try:
        host = urlparse(url).netloc.lower().lstrip("www.")
    except Exception:
        return "Could not parse URL."
    if host not in ALLOWED_DOMAINS:
        return f"Domain {host!r} is not in the fetch allowlist."
    return None

