import hashlib, time
from typing import Any

_SEARCH_CACHE: dict[str, tuple[float, Any]] = {}
_SEARCH_TTL = 600  # 10 minutes

def search_web_cached(query: str, count: int = 5) -> dict:
    key = hashlib.md5(f"{query}:{count}".encode()).hexdigest()
    now = time.monotonic()
    if key in _SEARCH_CACHE:
        exp, result = _SEARCH_CACHE[key]
        if now < exp:
            return {**result, "cached": True}
    result = search_web(query, count)
    if "error" not in result:  # only cache successes
        _SEARCH_CACHE[key] = (now + _SEARCH_TTL, result)
    return result

